mapper.select:
SELECT ss.id, ss.subject_id, ss.day_of_week, ss.start_time, ss.end_time, ss.room, ss.semester, sub.subject_name FROM schedule_slot ss LEFT JOIN subject sub ON ss.subject_id = sub.id
AND ss.semester = #{semester}
ORDER BY ss.day_of_week, ss.start_time

SELECT ss.id, ss.subject_id, ss.day_of_week, ss.start_time, ss.end_time, ss.room, ss.semester, sub.subject_name FROM schedule_slot ss JOIN subject sub ON ss.subject_id = sub.id JOIN enrollment e ON e.subject_id = ss.subject_id AND e.semester = ss.semester WHERE e.student_id = #{studentId}
AND ss.semester = #{semester}
ORDER BY ss.day_of_week, ss.start_time

mapper.update:
UPDATE schedule_slot
SET subject_id = #{subjectId}, day_of_week = #{dayOfWeek},
    start_time = #{startTime}, end_time = #{endTime},
    room = #{room}, semester = #{semester}
WHERE id = #{id}
